1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty list when given empty list", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells, each with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]])).toContainEqual([1, 0]);
16	  });
17	  it("should kill the center cell of a 3x3 block which has more than 3 live neighbors (overpopulation)", () => {
18	    const result = nextGeneration([
19	      [0, 0], [1, 0], [2, 0],
20	      [0, 1], [1, 1], [2, 1],
21	      [0, 2], [1, 2], [2, 2],
22	    ]);
23	    expect(result).not.toContainEqual([1, 1]);
24	  });
25	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
26	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
27	    expect(result).toContainEqual([1, 1]);
28	  });
29	  it("should keep a 2x2 block unchanged (still life)", () => {
30	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    const result = nextGeneration(block);
32	    expect(result).toHaveLength(4);
33	    for (const cell of block) {
34	      expect(result).toContainEqual(cell);
35	    }
36	  });
37	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
38	  it.todo("should handle negative coordinates correctly");
39	});
