1	type Cell = [number, number];
2	
3	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
4	
5	const neighborOffsets: ReadonlyArray<[number, number]> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [0, -1],           [0, 1],
8	  [1, -1],  [1, 0],  [1, 1],
9	];
10	
11	const isNeighbor = (cell: Cell, other: Cell): boolean => {
12	  const [x, y] = cell;
13	  const [ox, oy] = other;
14	  return (ox !== x || oy !== y) && Math.abs(ox - x) <= 1 && Math.abs(oy - y) <= 1;
15	};
16	
17	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
18	  liveCells.filter((other) => isNeighbor(cell, other)).length;
19	
20	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
21	  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
22	
23	const candidateCells = (liveCells: Cell[]): Cell[] => {
24	  const seen = new Set<string>();
25	  const candidates: Cell[] = [];
26	  for (const [x, y] of liveCells) {
27	    const neighborhood: Cell[] = [[x, y], ...neighborOffsets.map(([dx, dy]): Cell => [x + dx, y + dy])];
28	    for (const candidate of neighborhood) {
29	      const key = cellKey(candidate);
30	      if (!seen.has(key)) {
31	        seen.add(key);
32	        candidates.push(candidate);
33	      }
34	    }
35	  }
36	  return candidates;
37	};
38	
39	const survivesOrIsBorn = (cell: Cell, liveCells: Cell[]): boolean => {
40	  const liveNeighbors = countLiveNeighbors(cell, liveCells);
41	  return isLive(cell, liveCells)
42	    ? liveNeighbors === 2 || liveNeighbors === 3
43	    : liveNeighbors === 3;
44	};
45	
46	export function nextGeneration(cells: Cell[]): Cell[] {
47	  return candidateCells(cells).filter((cell) => survivesOrIsBorn(cell, cells));
48	}
